402|export function buildDashboardSnapshot(input: {
403|  period: DashboardPeriod;
404|  orders: DashboardOrderRow[];
405|  orderItems?: DashboardOrderItemRow[];
406|  metrics: DashboardMetricRow[];
407|  connectorAccounts?: DashboardConnectorRow[];
408|  inventory?: {
409|    productName: string;
410|    quantity: number | null;
411|    sku?: string | null;
412|    categoryName?: string | null;
413|  }[];
414|  trafficProviders?: ConnectorProvider[];
415|  commerceProviders?: ConnectorProvider[];
416|}): DashboardSnapshot {
417|  const { period } = input;
418|  // Product catalog (stock + category) synced from the workspace's store
419|  // connectors. Keyed by SKU (preferred — survives "Produto - VARIANTE" name
420|  // drift) and by normalized name (fallback). Used to fill the products table's
421|  // "Estoque disponível" column and to enrich each order item's category for the
422|  // Categorias widget.
423|  // ponytail: quantities SUM across connectors — a multi-store workspace's
424|  // total on-hand. If a SKU is shared across stores this is the combined stock,
425|  // not a double-count; switch to MAX only if stores mirror the same warehouse.
426|  // Stock accumulator per product key. `hasNumber` tracks whether any matching
427|  // catalog row reported a tracked count; `hasUnlimited` whether any row was
428|  // untracked (sells unlimited). When no row tracked a count — or every tracked
429|  // row summed to 0 while an unlimited source exists — the product resolves to
430|  // "unlimited" ("Disponível") rather than a false out-of-stock 0.
431|  type StockAcc = { sum: number; hasNumber: boolean; hasUnlimited: boolean };
432|  const inventoryQtyByName = new Map<string, StockAcc>();
433|  const inventoryQtyBySku = new Map<string, StockAcc>();
434|  const categoryByName = new Map<string, string>();
435|  const categoryBySku = new Map<string, string>();
436|  const accumulateStock = (
437|    map: Map<string, StockAcc>,
438|    key: string,
439|    quantity: number | null,
440|  ): void => {
441|    const entry = map.get(key) ?? {
442|      sum: 0,
443|      hasNumber: false,
444|      hasUnlimited: false,
445|    };
446|    if (quantity === null) {
447|      entry.hasUnlimited = true;
448|    } else {
449|      entry.sum += quantity;
450|      entry.hasNumber = true;
451|    }
452|    map.set(key, entry);
453|  };
454|  for (const item of input.inventory ?? []) {
455|    const nameKey = item.productName.trim().toLowerCase();
456|    const skuKey = item.sku?.trim().toLowerCase() || "";
457|    if (nameKey) {
458|      accumulateStock(inventoryQtyByName, nameKey, item.quantity);
459|    }
460|    if (skuKey) {
461|      accumulateStock(inventoryQtyBySku, skuKey, item.quantity);
462|    }
463|    const category = item.categoryName?.trim();
464|    if (category) {
465|      if (nameKey && !categoryByName.has(nameKey)) {
466|        categoryByName.set(nameKey, category);
467|      }
468|      if (skuKey && !categoryBySku.has(skuKey)) {
469|        categoryBySku.set(skuKey, category);
470|      }
471|    }
472|  }
473|  // Resolve a product's on-hand stock: SKU match first, then name.
474|  //   number      → tracked on-hand count (renders the number)
475|  //   "unlimited" → matched but the store doesn't track stock (renders
476|  //                 "Disponível")
477|  //   null        → no catalog row matched (renders "Sem dado")
478|  // A tracked count wins only when it's positive; a tracked-zero that coexists
479|  // with an unlimited source is still "available" (don't show a false 0).
480|  const accToStock = (acc: StockAcc): number | "unlimited" => {
481|    if (acc.hasNumber && (acc.sum > 0 || !acc.hasUnlimited)) {
482|      return acc.sum;
483|    }
484|    return "unlimited";
485|  };
486|  const resolveStock = (
487|    productName: string,
488|    sku: string | null | undefined,
489|  ): number | "unlimited" | null => {
490|    const skuKey = sku?.trim().toLowerCase() || "";
491|    const bySku = skuKey ? inventoryQtyBySku.get(skuKey) : undefined;
492|    if (bySku) {
493|      return accToStock(bySku);
494|    }
495|    const nameKey = productName.trim().toLowerCase();
496|    const byName = inventoryQtyByName.get(nameKey);
497|    return byName ? accToStock(byName) : null;
498|  };
499|  // Resolve a product's category: explicit order-item category wins, then
500|  // catalog by SKU, then catalog by name.
501|  const resolveCategoryName = (
502|    productName: string,
503|    sku: string | null | undefined,
504|    explicit: string | null | undefined,
505|  ): string | null => {
506|    const fromItem = explicit?.trim();
507|    if (fromItem) return fromItem;
508|    const skuKey = sku?.trim().toLowerCase() || "";
509|    if (skuKey && categoryBySku.has(skuKey)) {
510|      return categoryBySku.get(skuKey) ?? null;
511|    }
512|    const nameKey = productName.trim().toLowerCase();
513|    return categoryByName.get(nameKey) ?? null;
514|  };
515|  const trafficProviders = input.trafficProviders ?? [
516|    ...dashboardTrafficProviders,
517|  ];
518|  const commerceProviders = input.commerceProviders ?? [
519|    ...dashboardCommerceProviders,
520|  ];
521|  const connectorNames = new Map(
522|    (input.connectorAccounts ?? []).map(
523|      (account) => [account.id, account] as const,
524|    ),
